// Apply before React hydrates to prevent flash
applyTheme(readStoredThemeId());

interface ThemeContextValue {
  themeId: ThemeId;
  theme: ThemeDefinition;
  setThemeId: (id: ThemeId) => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [themeId, setThemeIdState] = useState<ThemeId>(readStoredThemeId);

  const setThemeId = useCallback((id: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(id, true);
    setThemeIdState(id);
  }, []);

  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key !== STORAGE_KEY) return;
      const next = readStoredThemeId();
      applyTheme(next, true);
      setThemeIdState(next);
    };
    window.addEventListener("storage", handleStorage);
    return () => window.removeEventListener("storage", handleStorage);
  }, []);

  return (
    <ThemeContext.Provider value={{ themeId, theme: getThemeById(themeId), setThemeId }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error("useTheme must be used within ThemeProvider");
  return ctx;
}
```

### Step 4 — `apps/web/src/hooks/useTheme.ts` (replace entirely)

The file becomes a one-liner re-export. All existing import paths (`../hooks/useTheme`) keep
working; callers are updated where needed (settings page is the only consumer).

```ts
